// Add this at the top of the file
const USE_MOCK = process.env.REACT_APP_USE_MOCK === 'true' || true; // Set to false when backend is ready

// Mock data
const mockData = {
  dashboard: {
    totalConversations: 1247,
    activeConversations: 23,
    totalDocuments: 156,
    totalLeads: 89,
    recentActivities: [
      { time: '2 minutes ago', description: 'New lead captured from WhatsApp', status: 'success' },
      { time: '15 minutes ago', description: 'Document "FAQ v2" uploaded', status: 'info' },
      { time: '1 hour ago', description: 'Conversation escalated to support', status: 'warning' },
    ],
    weeklyData: [65, 59, 80, 81, 56, 55, 40],
    sentimentData: [60, 30, 10],
  }
};

// Mock the dashboard stats
export const getDashboardStats = async () => {
  if (USE_MOCK) {
    return Promise.resolve({ data: { success: true, data: mockData.dashboard } });
  }
  return api.get('/dashboard/stats');
};




